1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type DamageEntry = { itemType: string; amount: number };
3	type Incident = { cause: string; damages: DamageEntry[] };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	type QuoteResult = { premium: number };
10	type ClaimResult = { payout: number; remainingCap: number };
11	type StepResult = QuoteResult | ClaimResult;
12	
13	const PROCESSING_FEE = 5;
14	const FIRST_INSURANCE_RATE = 0.1;
15	const CURSE_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	const LOYALTY_DISCOUNT_RATE = 0.2;
19	const LOYALTY_THRESHOLD_YEARS = 2;
20	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
21	const DEDUCTIBLE = 100;
22	const HIGH_ENCHANTMENT_PAYOUT_THRESHOLD = 8;
23	const HIGH_ENCHANTMENT_PAYOUT_RATE = 0.5;
24	const BASE_PREMIUMS: Record<string, number> = {
25	  sword: 100,
26	  amulet: 60,
27	  staff: 80,
28	  potion: 40,
29	  rune: 25,
30	  moonstone: 25,
31	};
32	const INSURANCE_VALUES: Record<string, number> = {
33	  sword: 1000,
34	  amulet: 600,
35	  staff: 800,
36	  potion: 400,
37	  rune: 250,
38	  moonstone: 250,
39	};
40	
41	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
42	const BLOCK_SIZE = 3;
43	const BLOCK_BASE_PREMIUM = 60;
44	
45	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
46	
47	const unitInsuranceValue = (type: string): number => INSURANCE_VALUES[type] ?? 0;
48	
49	const isComponentBlock = (type: string, count: number): boolean =>
50	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
51	
52	const groupBasePremium = (type: string, count: number): number =>
53	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
54	
55	const countByType = (items: Item[]): Map<string, number> =>
56	  items.reduce(
57	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
58	    new Map<string, number>(),
59	  );
60	
61	const itemsBasePremium = (items: Item[]): number =>
62	  [...countByType(items)].reduce(
63	    (total, [type, count]) => total + groupBasePremium(type, count),
64	    0,
65	  );
66	
67	const itemModifierSurcharge = (item: Item): number => {
68	  const base = unitBasePremium(item.type);
69	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
70	  const highEnchantmentSurcharge =
71	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE : 0;
72	  return curseSurcharge + highEnchantmentSurcharge;
73	};
74	
75	const itemsModifierSurcharge = (items: Item[]): number =>
76	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
77	
78	const loyaltyDiscount = (base: number, customer: Customer): number =>
79	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? base * LOYALTY_DISCOUNT_RATE : 0;
80	
81	const followUpDiscount = (base: number, isFollowUp: boolean): number =>
82	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
83	
84	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
85	  const base = itemsBasePremium(items);
86	  const modifierSurcharge = itemsModifierSurcharge(items);
87	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
88	  const discount = loyaltyDiscount(base, customer) + followUpDiscount(base, isFollowUp);
89	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge - discount + PROCESSING_FEE);
90	};
91	
92	const insuranceSum = (items: Item[]): number =>
93	  items.reduce((total, item) => total + unitInsuranceValue(item.type), 0);
94	
95	type Policy = { items: Item[]; capRemaining: number };
96	
97	const createPolicy = (items: Item[]): Policy => ({
98	  items,
99	  capRemaining: 2 * insuranceSum(items),
100	});
101	
102	const findDamagedItem = (policy: Policy, itemType: string): Item | undefined =>
103	  policy.items.find((item) => item.type === itemType);
104	
105	const reimbursableAmount = (item: Item | undefined, damage: DamageEntry): number =>
106	  (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_PAYOUT_THRESHOLD
107	    ? damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATE
108	    : damage.amount;
109	
110	const damagePayout = (policy: Policy, damage: DamageEntry): number => {
111	  const item = findDamagedItem(policy, damage.itemType);
112	  return Math.max(0, reimbursableAmount(item, damage) - DEDUCTIBLE);
113	};
114	
115	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
116	  const rawPayout = incident.damages.reduce(
117	    (total, damage) => total + damagePayout(policy, damage),
118	    0,
119	  );
120	  const payout = Math.min(rawPayout, policy.capRemaining);
121	  policy.capRemaining -= payout;
122	  return { payout: Math.floor(payout), remainingCap: policy.capRemaining };
123	};
124	
125	const priorQuoteCount = (steps: Step[], upTo: number): number =>
126	  steps.slice(0, upTo).filter((s) => s.op === "quote").length;
127	
128	const handleQuote = (
129	  step: QuoteStep,
130	  index: number,
131	  scenario: Scenario,
132	  policies: Map<number, Policy>,
133	): QuoteResult => {
134	  const isFollowUp = priorQuoteCount(scenario.steps, index) > 0;
135	  policies.set(index, createPolicy(step.items));
136	  return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
137	};
138	
139	const handleClaim = (step: ClaimStep, policies: Map<number, Policy>): ClaimResult => {
140	  const policy = policies.get(step.policy);
141	  if (!policy) throw new Error(`No policy at index ${step.policy}`);
142	  return processClaim(policy, step.incident);
143	};
144	
145	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
146	  const policies = new Map<number, Policy>();
147	  const results: StepResult[] = scenario.steps.map((step, index) =>
148	    step.op === "quote"
149	      ? handleQuote(step, index, scenario, policies)
150	      : handleClaim(step, policies),
151	  );
152	  return { results };
153	};
